column109:
14/Jan/26 7:36 AM;712020:8bed8d8d-8a55-42b7-b3c8-8062e9fcedef;* Scripts para agregar el pais de procedencia y origen en la solicitud

Obtener formulario y producto de acuerdo a numero de referencia y estado

{noformat}select f.id, f.referencia, f.estado, p.id from procesos.formulario f, procesos.producto p where f.referencia = 'VAL-0001CE/26-1' and f.estado = 'Evaluacion' and p.formulario_id = f.id;{noformat}

 
Obtener id del pais a agregar

{noformat}select p.id, p.nombre from administrador.pais p where p.nombre = 'MEXICO'{noformat}


Insertar pais origen en el formulario

{noformat}INSERT INTO procesos.pais_origen (producto_id, pais_id) VALUES(2319, 144);{noformat}

 

Insertar pais procedencia en el formulario

{noformat}INSERT INTO procesos.pais_procedencia (producto_id, pais_id) VALUES(2319, 144);{noformat}

column110:
14/Jan/26 7:37 AM;712020:8bed8d8d-8a55-42b7-b3c8-8062e9fcedef;Scripts para actualizar el analista

Obtener formulario de acuerdo a la referencia

{noformat}select f.id, f.referencia, f.analista_id, u."name", u.email, u.id from procesos.formulario f, administrador.users u where f.referencia = 'EL-0001CE/26-1' and f.analista_id = u.id;{noformat}

 

Obtener usuario analista con nombre de Fabricio (buscar id)

{noformat}select u."name", u.id from administrador.users u, administrador.user_permiso up, administrador.permiso p, administrador.rol r where u."name" like '%Fabricio%' and up.user_id = u.id and up.permiso_id = p.id and p.rol_id = r.id and r.nombre = 'Analista' limit 1;{noformat}

 

Actualizar analista en el formulario

{noformat}UPDATE procesos.formulario SET analista_id=7 WHERE id=2315;{noformat}

